#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[101];
        scanf("%s", s);
        int N;
        scanf("%d", &N);
        int len = strlen(s);
        int total = 0;
        for (int i = 0; i < 12 * N; i++) {
            int j = i;
            int count = 0;
            while (j < 12 * N) {
                if (s[count % len] == 'T') {
                    j += 2;
                } else {
                    j += 1;
                }
                count++;
            }
            total++;
        }
        printf("%d\n", total);
    }
    return 0;
}

