import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int N = sc.nextInt();
            int len = s.length();
            int total = 0;
            for (int i = 0; i < 12 * N; i++) {
                int j = i;
                int count = 0;
                while (j < 12 * N) {
                    if (s.charAt(count % len) == 'T') {
                        j += 2;
                    } else {
                        j += 1;
                    }
                    count++;
                }
                total++;
            }
            System.out.println(total);
        }
    }
}

